using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpApiServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo weather REST API.
/// The MCP SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods at startup.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    // HttpClient is constructor-injected by the DI container.
    // Register it via IHttpClientFactory in Program.cs so the runtime
    // manages handler lifetimes and pooling automatically.
    private readonly HttpClient _http;

    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool("get_weather")]
    [Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetWeatherAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&current=temperature_2m,wind_speed_10m";

        var result = await _http.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (result?.Current is null)
            return "No weather data available for the given coordinates.";

        return $"Temperature: {result.Current.Temperature}°C, "
             + $"Wind speed: {result.Current.WindSpeed} km/h";
    }

    [McpServerTool("get_forecast")]
    [Description("Get a 7-day daily temperature forecast for a location.")]
    public async Task<string> GetForecastAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min"
                + $"&timezone=auto";

        var result = await _http.GetFromJsonAsync<ForecastResponse>(url, cancellationToken);

        if (result?.Daily is null)
            return "No forecast data available.";

        var lines = result.Daily.Time.Select((date, i) =>
            $"{date}: {result.Daily.TempMin[i]}–{result.Daily.TempMax[i]}°C");

        return string.Join("\n", lines);
    }

    // --- JSON models for the Open-Meteo API ---

    private sealed class WeatherResponse
    {
        [JsonPropertyName("current")]
        public CurrentWeather? Current { get; set; }
    }

    private sealed class CurrentWeather
    {
        [JsonPropertyName("temperature_2m")]
        public double Temperature { get; set; }

        [JsonPropertyName("wind_speed_10m")]
        public double WindSpeed { get; set; }
    }

    private sealed class ForecastResponse
    {
        [JsonPropertyName("daily")]
        public DailyForecast? Daily { get; set; }
    }

    private sealed class DailyForecast
    {
        [JsonPropertyName("time")]
        public string[] Time { get; set; } = [];

        [JsonPropertyName("temperature_2m_max")]
        public double[] TempMax { get; set; } = [];

        [JsonPropertyName("temperature_2m_min")]
        public double[] TempMin { get; set; } = [];
    }
}

